import { OrderDetailDataAttributeDto } from '../api';
import { UIElement } from '../models/ui.model';

export function mapOrderDetailElements(
  dto: OrderDetailDataAttributeDto[],
): UIElement[] {
  const attrs: { [K: string]: string } = {};

  for (const element of dto) {
    if (!element) continue;
    const { values, key } = element;
    if (typeof key === 'string' && key) {
      if (typeof values === 'string' || typeof values === 'number') {
        if (values !== '') {
          attrs[key] = `${values}`;
        }
      }
    }
  }

  const elements: UIElement[] = [];

  const valorDolarText = attrs['valor dolar'];

  if (valorDolarText) {
    elements.push({
      type: 'KeyValueRow',
      props: {
        label: 'Valor em dólar',
        value: `US$ ${valorDolarText}`,
        showDivider: true,
      },
    });
  }

  const vehicleText = (() => {
    const marca = attrs['marca veiculo'] ?? '';
    const modelo = attrs['modelo veiculo'] ?? '';
    const placa = attrs['placa veiculo'] ?? '';

    const vehicle = [
      marca,
      modelo,
    ]
      .filter(Boolean)
      .join(' ');

    if (!vehicle && !placa) return '';

    return placa ? `${vehicle} - ${placa}` : vehicle;
  })();

  if (vehicleText) {
    elements.push({
      type: 'KeyValueRow',
      props: {
        label: 'Tag',
        value: vehicleText,
        showDivider: true,
      },
    });
  }

  const razaoUsoText = attrs['razao uso tag'];
  if (razaoUsoText) {
    elements.push({
      type: 'KeyValueRow',
      props: {
        label: 'Tipo de compra',
        value: razaoUsoText,
        showDivider: true,
      },
    });
  }

  return elements;
}

