/**
 * @file Type definitions for reusable UI display configurations.
 */

import type * as _DS from '@semparar/design-system-app';
import type React from 'react';

export type DS = typeof _DS;

/**
 * Extract component Props
 */
export type ComponentProps<T> = T extends (
  props: infer Props extends object,
) => React.ReactNode
  ? Props
  : never;

/**
 * Maps Design System component names to their props.
 * @example DSComponents['Text'] → { type: string; color: string; ... }
 */
export type DSComponents = {
  // Filtering elements with capitalized names that looks like a React.FC<>
  -readonly [K in keyof DS as K extends Capitalize<string>
    ? DS[K] extends (props: object) => React.ReactNode
      ? K
      : never
    : never]: DS[K] extends unknown ? ComponentProps<DS[K]> : never;
} & {};

/**
 * JSON-compatible value for UI element props.
 */
export type UIParamValue =
  | string
  | boolean
  | number
  | null
  | undefined
  | { [K: string]: UIParamValue }
  | ArrayLike<UIParamValue>;

/**
 * JSON-compatible UI props.
 */
export type UIParams = { [K: string]: UIParamValue };

/**
 * Base type for a UI element configuration.
 */
export type UIElementConfig<
  Type extends string = string,
  Props extends UIParams = {},
> = {
  type: Type;
  props: Props;
};

/**
 * Registry of available UI element configurations.
 */
export type UIElements = {
  KeyValueRow: UIElementConfig<
    'KeyValueRow',
    {
      label: string;
      value: string;
      showDivider?: boolean;
      labelType?: DSComponents['Text']['type'];
      labelColor?: DSComponents['Text']['color'];
      valueType?: DSComponents['Text']['type'];
      valueColor?: DSComponents['Text']['color'];
    }
  >;
};

export type UIElement = UIElements[keyof UIElements];

