 13→import type { ScreenProps } from '../../routes/Models';
 14→import { OrderDetailStatus, type TransactionType } from '../../services/models';
 15→import { moment } from '../../services/moment';
 16→import { getOrderDetail } from '../../services/services';
 17→import { formatToCurrency } from '../../utils/functions';
 18→import {
 19→  MY_ORDERS_DETAILS_EVENT_MODAL_VIEW_REPORT_PROBLEM,
 20→  MY_ORDERS_DETAILS_EVENT_SCREEN_VIEW_V3_DATA,
 21→  MY_ORDERS_DETAILS_EVENT_SELECT_CONTENT_REPORT_PROBLEM,
 22→} from './Data';
 23→import type { MarketplaceContentData, MarketplaceItemData } from './Models';
 24→import { STATUS_COLORS } from './Models';
 25→import {
 26→  getCleanedImageUrl,
 27→  getFormattedHighlightText,
 28→  getFormattedPointsValue,
 29→  getFormattedPointsValueForMarketplace,
 30→  getMarketplaceTitle,
 31→  getPaymentTypeLabel,
 32→  getTransactionGainType,
 33→} from './utils';
 34→import MyOrdersDetailView from './view';
 35→
 36→const MyOrdersDetails = ({ route }: ScreenProps<'MyOrdersDetails'>) => {
 37→  const navigation = useNavigation();
 38→  const hasFocused = useRef(false);
 39→  const modalizeRef = useRef<PropsModalizeRef>(null);
 40→  const modalizeRefInfo = useRef<PropsModalizeRef>(null);
 41→
 42→  const { orderDetail, orderDetailActions } = useRootStore(
 43→    useShallow(state => ({
 44→      orderDetail: state.orderDetail,
 45→      orderDetailActions: state.orderDetailActions,
 46→    })),
 47→  );
 48→
 49→  const transactionId = route.params?.transactionId;
 50→  const passedType = route.params?.type;
 51→  const passedIcon = route.params?.icon;
 52→  const passedStatus = route.params?.status;
 53→  const passedOrigination = route.params?.origination;
 54→  const passedOrigin = route.params?.origin;
 55→
 56→  const { screenTitle, typeButtonReportProblem } =
 57→    useExtractDetailRewardProgram(
 58→      orderDetail.orderDetail,
 59→      passedOrigin as 'order' | 'extract',
 60→      orderDetail.status === OrderDetailStatus.LOADING,
 61→    );
 62→
 63→  const hasOrder = useMemo(() => {
 64→    return passedOrigin === 'order';
 65→  }, [passedOrigin]);
 66→
 67→  useFocusEffect(
 68→    useCallback(() => {
 69→      const eventScreenViewV3Data =
 70→        MY_ORDERS_DETAILS_EVENT_SCREEN_VIEW_V3_DATA[
 71→          passedOrigin as 'order' | 'extract'
 72→        ];
 73→      if (!hasFocused.current) {
 74→        eventScreenViewV3(...eventScreenViewV3Data);
