101→        passedOrigin as 'order' | 'extract'
102→      ],
103→    );
104→    eventModalView(
105→      MY_ORDERS_DETAILS_EVENT_MODAL_VIEW_REPORT_PROBLEM[
106→        passedOrigin as 'order' | 'extract'
107→      ],
