127→      content_type: 'cta',
128→      content_id: 'telefones_demais_localidades',
129→      location_1: 'monetizacao',
130→      location_2: 'hub_recompensas_spmais',
131→      location_3: hasOrder ? 'contato_telefones_pedido' : 'contato_telefones',
132→    });
