161→    type: string | undefined,
162→  ): type is TransactionType => {
163→    return (
164→      type === 'CREDIT' ||
165→      type === 'RESCUE' ||
166→      type === 'EXPIRED' ||
167→      type === 'REFUNDED'
168→    );
169→  };
170→
171→  const enrichedTransaction = transaction
172→    ? {
