210→        ? `- ${getFormattedPointsValueForMarketplace(marketplaceValuePoints)}`
211→        : getFormattedPointsValue(
212→            enrichedTransaction.amount,
213→            enrichedTransaction.type,
214→          );
215→    const marketplaceTitle = getMarketplaceTitle(enrichedTransaction);
216→    const cardTitle = marketplaceTitle || enrichedTransaction.description || '';
217→    const highlightText = getFormattedHighlightText(
218→      enrichedTransaction.date,
