import { TagLabel } from '@semparar/design-system-app';
import React from 'react';
import { KeyValueRow } from '../../atoms/KeyValueRow';
import type { UIElementListProps } from './Models';
import { useUIElementList } from './index';

const UI_ELEMENT_REGISTRY = {
  KeyValueRow,
  TagLabel: (props: { text: string; type?: string; showSpacing?: boolean; icon?: string; showDivider?: boolean }) => {
    const { showDivider: _showDivider, ...tagProps } = props;
    return <TagLabel {...tagProps as never} />;
  },
} as const;

export default function UIElementListView(props: UIElementListProps) {
  const { elements } = useUIElementList(props);

  return (
    <>
      {elements.map((element, idx) => {
        const Component = UI_ELEMENT_REGISTRY[element.type];
        if (!Component) return null;
        return <Component key={`${element.type}-${idx}`} {...element.props as never} />;
      })}
    </>
  );
}

