import type { TypesTagLabel } from '@semparar/design-system-app/src/atomic/molecules/TagLabel/Models';
import type { UIElement } from '../models/ui.model';

interface OrderDetailViewParams {
  highlightText: string;
  hasOrder: boolean;
  showOrderNumber: boolean;
  transactionId?: string;
  showStatus: boolean;
  transactionStatus?: string;
  statusColor?: TypesTagLabel;
  showValue: boolean;
  formattedCurrencyValue: string;
}

export function mapOrderDetailViewElements(
  params: OrderDetailViewParams,
): UIElement[] {
  const {
    highlightText,
    hasOrder,
    showOrderNumber,
    transactionId,
    showStatus,
    transactionStatus,
    statusColor,
    showValue,
    formattedCurrencyValue,
  } = params;

  const elements: UIElement[] = [];

  if (highlightText) {
    elements.push({
      type: 'TagLabel',
      props: {
        type: 'neutral',
        text: highlightText,
        showSpacing: true,
      },
    });
  }

  if (hasOrder && showOrderNumber && transactionId) {
    elements.push({
      type: 'KeyValueRow',
      props: {
        label: 'Número do pedido',
        value: `#${transactionId}`,
        showDivider: false,
      },
    });
  }

  if (hasOrder && showStatus && transactionStatus) {
    elements.push({
      type: 'TagLabel',
      props: {
        text: transactionStatus,
        type: statusColor ?? 'neutral',
        showSpacing: true,
        showDivider: true,
      },
    });
  }

  if (showValue) {
    elements.push({
      type: 'KeyValueRow',
      props: {
        label: 'Valor',
        value: formattedCurrencyValue,
        showDivider: hasOrder,
      },
    });
  }

  return elements;
}

